  return {
    isOwnerExecutionCommand: true,
    autoExecute: true,
    requiresApproval: false,
    approvalCategories: [],
    reason: 'non-destructive',
    systemMode: true,
    matchedTriggers: ['fix this'],
    safeCategories: [],
    ...overrides,
